document.addEventListener("keydown", function(e){

if(e.key === "ArrowRight"){
flipNext()
}

if(e.key === "ArrowLeft"){
flipPrev()
}

})

let currentPage = 0

const pages = document.querySelectorAll(".page")

function flipNext(){

if(currentPage < pages.length-1){

pages[currentPage].classList.remove("active")

currentPage++

pages[currentPage].classList.add("active")

}

}

function flipPrev(){

if(currentPage > 0){

pages[currentPage].classList.remove("active")

currentPage--

pages[currentPage].classList.add("active")

}

}
